async fn test_middleware_app_data() {
    let srv = init_service(
        App::new().service(
            web::resource("test")
                .app_data(1usize)
                .wrap_fn(|req, srv| {
                    assert_eq!(req.app_data::<usize>(), Some(&1usize));
                    req.extensions_mut().insert(1usize);
                    srv.call(req)
                })
                .route(web::get().to(HttpResponse::Ok))
                .default_service(|req: ServiceRequest| async move {
                    let (req, _) = req.into_parts();

                    assert_eq!(req.extensions().get::<usize>(), Some(&1));

                    Ok(ServiceResponse::new(
                        req,
                        HttpResponse::BadRequest().finish(),
                    ))
                }),
        ),
    )
    .await;

    let req = TestRequest::get().uri("/test").to_request();
    let resp = call_service(&srv, req).await;
    assert_eq!(resp.status(), StatusCode::OK);

    let req = TestRequest::post().uri("/test").to_request();
    let resp = call_service(&srv, req).await;
    assert_eq!(resp.status(), StatusCode::BAD_REQUEST);
}

fn search_path<M: Matcher, W: WriteColor>(
    matcher: M,
    searcher: &mut grep::searcher::Searcher,
    printer: &mut Printer<W>,
    path: &Path,
) -> io::Result<SearchResult> {
    match *printer {
        Printer::Standard(ref mut p) => {
            let mut sink = p.sink_with_path(&matcher, path);
            searcher.search_path(&matcher, path, &mut sink)?;
            Ok(SearchResult {
                has_match: sink.has_match(),
                stats: sink.stats().map(|s| s.clone()),
            })
        }
        Printer::Summary(ref mut p) => {
            let mut sink = p.sink_with_path(&matcher, path);
            searcher.search_path(&matcher, path, &mut sink)?;
            Ok(SearchResult {
                has_match: sink.has_match(),
                stats: sink.stats().map(|s| s.clone()),
            })
        }
        Printer::JSON(ref mut p) => {
            let mut sink = p.sink_with_path(&matcher, path);
            searcher.search_path(&matcher, path, &mut sink)?;
            Ok(SearchResult {
                has_match: sink.has_match(),
                stats: Some(sink.stats().clone()),
            })
        }
    }
}

pub(crate) fn after_context_by_line(
    &mut self,
    buf: &[u8],
    upto: usize,
) -> Result<bool, S::Error> {
    if self.after_context_left == 0 {
        return Ok(true);
    }
    let exceeded_match_limit = self.has_exceeded_match_limit();
    let range = Range::new(self.last_line_visited, upto);
    let mut stepper = LineStep::new(
        self.config.line_term.as_byte(),
        range.start(),
        range.end(),
    );
    while let Some(line) = stepper.next_match(buf) {
        if exceeded_match_limit
            && self.is_match(&buf[line])? != self.config.invert_match
        {
            let after_context_left = self.after_context_left;
            self.set_pos(line.end());
            if !self.sink_matched(buf, &line)? {
                return Ok(false);
            }
            self.after_context_left = after_context_left - 1;
        } else if !self.sink_after_context(buf, &line)? {
            return Ok(false);
        }
        if self.after_context_left == 0 {
            break;
        }
    }
    Ok(true)
}

pub(crate) fn with_capacity(cap: usize) -> Self {
    assert!(cap > 0, "capacity must be positive");

    // Compute constants `mark_bit` and `one_lap`.
    let mark_bit = (cap + 1).next_power_of_two();
    let one_lap = mark_bit * 2;

    // Head is initialized to `{ lap: 0, mark: 0, index: 0 }`.
    let head = 0;
    // Tail is initialized to `{ lap: 0, mark: 0, index: 0 }`.
    let tail = 0;

    // Allocate a buffer of `cap` slots initialized
    // with stamps.
    let buffer: Box<[Slot<T>]> = (0..cap)
        .map(|i| {
            // Set the stamp to `{ lap: 0, mark: 0, index: i }`.
            Slot {
                stamp: AtomicUsize::new(i),
                msg: UnsafeCell::new(MaybeUninit::uninit()),
            }
        })
        .collect();

    Self {
        buffer,
        one_lap,
        mark_bit,
        head: CachePadded::new(AtomicUsize::new(head)),
        tail: CachePadded::new(AtomicUsize::new(tail)),
        senders: SyncWaker::new(),
        receivers: SyncWaker::new(),
    }
}

async fn insert_cache_asset(
  db: Arc<Mutex<Connection>>,
  put: CachePutRequest,
  response_body_key: Option<String>,
) -> Result<Option<String>, CacheError> {
  spawn_blocking(move || {
    let maybe_response_body = {
      let db = db.lock();
      db.query_row(
        "INSERT OR REPLACE INTO request_response_list
             (cache_id, request_url, request_headers, response_headers,
              response_body_key, response_status, response_status_text, last_inserted_at)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8)
             RETURNING response_body_key",
        (
          put.cache_id,
          put.request_url,
          serialize_headers(&put.request_headers),
          serialize_headers(&put.response_headers),
          response_body_key,
          put.response_status,
          put.response_status_text,
          SystemTime::now().duration_since(UNIX_EPOCH).expect("SystemTime is before unix epoch").as_secs(),
        ),
        |row| {
          let response_body_key: Option<String> = row.get(0)?;
          Ok(response_body_key)
        },
      )?
    };
    Ok::<Option<String>, CacheError>(maybe_response_body)
  }).await?
}

fn git_ignore_tree() {
  let sys = InMemorySys::default();
  sys.fs_create_dir_all("/sub_dir/sub_dir").unwrap();
  sys.fs_write("/.gitignore", "file.txt").unwrap();
  sys.fs_write("/sub_dir/.gitignore", "data.txt").unwrap();
  sys
    .fs_write("/sub_dir/sub_dir/.gitignore", "!file.txt\nignore.txt")
    .unwrap();
  let mut ignore_tree = GitIgnoreTree::new(&sys, Vec::new());
  let mut run_test = |path: &str, expected: bool| {
    let path = PathBuf::from(path);
    let gitignore =
      ignore_tree.get_resolved_git_ignore_for_file(&path).unwrap();
    assert_eq!(
      gitignore.is_ignored(&path, /* is_dir */ false),
      expected,
      "Path: {}",
      path.display()
    );
  };
  run_test("/file.txt", true);
  run_test("/other.txt", false);
  run_test("/data.txt", false);
  run_test("/sub_dir/file.txt", true);
  run_test("/sub_dir/other.txt", false);
  run_test("/sub_dir/data.txt", true);
  run_test("/sub_dir/sub_dir/file.txt", false); // unignored up here
  run_test("/sub_dir/sub_dir/sub_dir/file.txt", false);
  run_test("/sub_dir/sub_dir/sub_dir/ignore.txt", true);
  run_test("/sub_dir/sub_dir/ignore.txt", true);
  run_test("/sub_dir/ignore.txt", false);
  run_test("/ignore.txt", false);
}

pub unsafe fn uv_stream_set_blocking(
  stream: *mut uv_stream_t,
  blocking: c_int,
) -> c_int {
  unsafe {
    let fd = if (*stream).r#type == uv_handle_type::UV_TTY {
      (*(stream as *mut uv_tty_t)).internal_fd
    } else {
      // TCP and other stream types
      match (*(stream as *mut uv_tcp_t)).internal_fd {
        Some(fd) => fd,
        None => return super::UV_EBADF,
      }
    };

    let flags = libc::fcntl(fd, libc::F_GETFL);
    if flags == -1 {
      return -(std::io::Error::last_os_error()
        .raw_os_error()
        .unwrap_or(libc::EINVAL));
    }
    let new_flags = if blocking != 0 {
      flags & !libc::O_NONBLOCK
    } else {
      flags | libc::O_NONBLOCK
    };
    if new_flags != flags && libc::fcntl(fd, libc::F_SETFL, new_flags) == -1 {
      return -(std::io::Error::last_os_error()
        .raw_os_error()
        .unwrap_or(libc::EINVAL));
    }
    0
  }
}

fn all_lint_rules_are_listed_in_schema_file() {
  let all_rules = get_all_rules();

  let rules_schema_path =
    util::root_path().join("cli/schemas/lint-rules.v1.json");
  let rules_schema_file =
    std::fs::read_to_string(&rules_schema_path).unwrap();

  let schema: RulesSchema = serde_json::from_str(&rules_schema_file).unwrap();

  const UPDATE_ENV_VAR_NAME: &str = "UPDATE_EXPECTED";

  let rules_list = schema.one_of.1.r#enum;

  if std::env::var(UPDATE_ENV_VAR_NAME).ok().is_none() {
    assert_eq!(
      rules_list, all_rules,
      "Lint rules schema file not up to date. Run again with {}=1 to update the expected output",
      UPDATE_ENV_VAR_NAME
    );
    return;
  }

  let new_schema = RulesSchema {
    schema: schema.schema,
    one_of: (schema.one_of.0, RulesEnum { r#enum: all_rules }),
  };

  std::fs::write(
    &rules_schema_path,
    format!("{}\n", serde_json::to_string_pretty(&new_schema).unwrap(),),
  )
  .unwrap();
}

extern "C" fn gc_epilogue_callback(
  isolate: v8::UnsafeRawIsolatePtr,
  gc_type: v8::GCType,
  _flags: v8::GCCallbackFlags,
  _data: *mut c_void,
) {
  // SAFETY: V8 guarantees the isolate is valid during this callback.
  let mut isolate =
    unsafe { v8::Isolate::from_raw_isolate_ptr_unchecked(isolate) };
  let Some(rc) = registry_rc(&isolate) else {
    return;
  };
  if rc.borrow().profilers.is_empty() {
    return;
  }
  let snapshot = capture_snapshot(&mut isolate);
  let now = Instant::now();
  let gc_type_str = gc_type_name(gc_type);
  let mut inner = rc.borrow_mut();
  for state in inner.profilers.values_mut() {
    let (Some(before), Some(start)) =
      (state.pending_before.take(), state.pending_start.take())
    else {
      continue;
    };
    let cost_ns = now.saturating_duration_since(start).as_nanos() as f64;
    state.statistics.push(GcStat {
      gc_type: gc_type_str,
      cost_ns,
      before,
      after: snapshot.clone(),
    });
  }
}

pub fn copy_dir_recursive<TSys: CopyDirRecursiveSys>(
  sys: &TSys,
  from: &Path,
  to: &Path,
) -> Result<(), std::io::Error> {
  let sys = sys.with_paths_in_errors();
  sys.fs_create_dir_all(to)?;
  let read_dir = sys.fs_read_dir(from)?;

  for entry in read_dir {
    let entry = entry?;
    let file_type = entry.file_type()?;
    let new_from = from.join(entry.file_name());
    let new_to = to.join(entry.file_name());

    if file_type.is_dir() {
      copy_dir_recursive(sys.as_ref(), &new_from, &new_to)?;
    } else if file_type.is_file()
      && let Err(err) = sys.fs_copy(&new_from, &new_to)
    {
      if deno_npm_cache::is_etxtbsy(&err) {
        // The destination file is a hardlink to a currently-executing
        // binary (ETXTBSY). Remove it first to break the hardlink,
        // then retry the copy which will create a new inode.
        let _ = sys.fs_remove_file(&new_to);
        sys.fs_copy(&new_from, &new_to)?;
      } else {
        return Err(err);
      }
    }
  }

  Ok(())
}

async fn package_info(
  &self,
  name: &str,
) -> Result<Arc<NpmPackageInfo>, NpmRegistryPackageInfoLoadError> {
  if let Some(data) = self.data.borrow_mut().get(name).cloned() {
    return Ok(data);
  }
  let file_path = packument_cache_filepath(name);
  if let Ok(data) = std::fs::read_to_string(&file_path)
    && let Ok(data) = serde_json::from_str::<Arc<NpmPackageInfo>>(&data)
  {
    self
      .data
      .borrow_mut()
      .insert(name.to_string(), data.clone());
    return Ok(data);
  }
  let url = packument_url(name);
  eprintln!("Downloading {}", url);
  let resp = reqwest::get(&url).await.unwrap();
  if resp.status() == StatusCode::NOT_FOUND {
    return Err(NpmRegistryPackageInfoLoadError::PackageNotExists {
      package_name: name.to_string(),
    });
  }
  let text = resp.text().await.unwrap();
  std::fs::write(&file_path, &text).unwrap();
  let data = serde_json::from_str::<Arc<NpmPackageInfo>>(&text).unwrap();
  self
    .data
    .borrow_mut()
    .insert(name.to_string(), data.clone());
  Ok(data)
}

pub async fn op_net_accept_tls(
  state: Rc<RefCell<OpState>>,
  #[smi] rid: ResourceId,
) -> Result<(ResourceId, IpAddr, IpAddr), NetError> {
  let resource = state
    .borrow()
    .resource_table
    .get::<NetworkListenerResource<TlsListener>>(rid)
    .map_err(|_| NetError::ListenerClosed)?;

  let cancel_handle = RcRef::map(&resource, |r| &r.cancel);
  let listener = RcRef::map(&resource, |r| &r.listener)
    .try_borrow_mut()
    .ok_or_else(|| NetError::AcceptTaskOngoing)?;

  let (tls_stream, remote_addr) =
    match listener.accept().try_or_cancel(&cancel_handle).await {
      Ok(tuple) => tuple,
      Err(err) if err.kind() == ErrorKind::Interrupted => {
        return Err(NetError::ListenerClosed);
      }
      Err(err) => return Err(err.into()),
    };

  let local_addr = tls_stream.local_addr()?;
  let rid = {
    let mut state_ = state.borrow_mut();
    state_
      .resource_table
      .add(TlsStreamResource::new_tcp(tls_stream.into_split()))
  };

  Ok((rid, IpAddr::from(local_addr), IpAddr::from(remote_addr)))
}

pub fn op_getgroups(state: &mut OpState) -> Result<Vec<u32>, OsError> {
  {
    let permissions = state.borrow_mut::<PermissionsContainer>();
    permissions.check_sys("gid", "node:process.getgroups()")?;
  }

  #[cfg(windows)]
  {
    Ok(vec![])
  }
  #[cfg(unix)]
  {
    // SAFETY: Call to libc getgroups with 0/null to query group count.
    let ngroups = unsafe { libc::getgroups(0, std::ptr::null_mut()) };
    if ngroups < 0 {
      return Err(OsError::FailedToGetGroups(std::io::Error::last_os_error()));
    }
    if ngroups == 0 {
      return Ok(vec![]);
    }
    let mut groups: Vec<libc::gid_t> = vec![0; ngroups as usize];
    // SAFETY: Call to libc getgroups with properly sized buffer.
    let ngroups = unsafe { libc::getgroups(ngroups, groups.as_mut_ptr()) };
    if ngroups < 0 {
      return Err(OsError::FailedToGetGroups(std::io::Error::last_os_error()));
    }
    groups.truncate(ngroups as usize);
    #[allow(
      clippy::unnecessary_cast,
      reason = "gid_t may not be u32 on all platforms"
    )]
    Ok(groups.iter().map(|&g| g as u32).collect())
  }
}

fn test_matmul() {
    // Verify that small matrix gets the right result.
    let a: Vec<f32> = vec![1.0, 2.0, 3.0, 4.0];
    let b: Vec<f32> = vec![5.0, 6.0, 7.0, 8.0];
    let mul: Vec<f32> = vec![19.0, 22.0, 43.0, 50.0];
    let mut dest = vec![0f32; 4];
    matmulz(&a[..], &b[..], &mut dest[..]);
    assert_eq!(mul, dest);

    seq_matmulz(&a[..], &b[..], &mut dest[..]);
    assert_eq!(mul, dest);

    matmul_strassen(&a[..], &b[..], &mut dest[..]);
    assert_eq!(mul, dest);

    // Verify that large matrix gets the same results in parallel and serial algorithms.
    let n = 1 << 14;
    assert!(n > MULT_CHUNK); // If we don't recurse we're not testing much.
    let a: Vec<f32> = (0..n).map(|i| (i % 101) as f32).collect();
    let b: Vec<f32> = (0..n).map(|i| (i % 101 + 7) as f32).collect();
    let mut seqmul = vec![0f32; n];
    seq_matmulz(&a[..], &b[..], &mut seqmul[..]);
    let mut rmul = vec![0f32; n];
    matmulz(&a[..], &b[..], &mut rmul[..]);
    assert_eq!(rmul, seqmul);

    // Verify strassen gets the same results.
    for d in rmul.iter_mut() {
        *d = 0.0;
    }
    matmul_strassen(&a[..], &b[..], &mut rmul[..]);
    assert_eq!(rmul, seqmul);
}

pub fn is_identity_modulo_regions(&self) -> bool {
    let mut var = ty::BoundVar::ZERO;
    for arg in self.var_values.iter() {
        match arg.kind() {
            ty::GenericArgKind::Lifetime(r) => {
                if matches!(r.kind(), ty::ReBound(ty::BoundVarIndexKind::Canonical, br) if var == br.var())
                {
                    var = var + 1;
                } else {
                    // It's ok if this region var isn't an identity variable
                }
            }
            ty::GenericArgKind::Type(ty) => {
                if matches!(ty.kind(), ty::Bound(ty::BoundVarIndexKind::Canonical, bt) if var == bt.var())
                {
                    var = var + 1;
                } else {
                    return false;
                }
            }
            ty::GenericArgKind::Const(ct) => {
                if matches!(ct.kind(), ty::ConstKind::Bound(ty::BoundVarIndexKind::Canonical, bc) if var == bc.var())
                {
                    var = var + 1;
                } else {
                    return false;
                }
            }
        }
    }

    true
}

fn bitor_assign(&mut self, other: Cfg) {
    match (&mut self.0, other.0) {
        (CfgEntry::Bool(true, _), _)
        | (_, CfgEntry::Bool(false, _))
        | (_, CfgEntry::Bool(true, _)) => {}
        (s @ CfgEntry::Bool(false, _), b) => *s = b,
        (CfgEntry::Any(a, _), CfgEntry::Any(ref mut b, _)) => {
            for c in b.drain(..) {
                if !a.iter().any(|a| a.is_equivalent_to(&c)) {
                    a.push(c);
                }
            }
        }
        (CfgEntry::Any(a, _), ref mut b) => {
            if !a.iter().any(|a| a.is_equivalent_to(b)) {
                a.push(mem::replace(b, CfgEntry::Bool(true, DUMMY_SP)));
            }
        }
        (s, CfgEntry::Any(mut a, _)) => {
            let b = mem::replace(s, CfgEntry::Bool(true, DUMMY_SP));
            if !a.iter().any(|a| a.is_equivalent_to(&b)) {
                a.push(b);
            }
            *s = CfgEntry::Any(a, DUMMY_SP);
        }
        (s, b) => {
            if !s.is_equivalent_to(&b) {
                let a = mem::replace(s, CfgEntry::Bool(true, DUMMY_SP));
                *s = CfgEntry::Any(thin_vec![a, b], DUMMY_SP);
            }
        }
    }
}

pub(super) fn expand_global_asm<'cx>(
    ecx: &'cx mut ExtCtxt<'_>,
    sp: Span,
    tts: TokenStream,
) -> MacroExpanderResult<'cx> {
    ExpandResult::Ready(match parse_args(ecx, sp, tts, AsmMacro::GlobalAsm) {
        Ok(args) => {
            let ExpandResult::Ready(mac) = expand_preparsed_asm(ecx, AsmMacro::GlobalAsm, args)
            else {
                return ExpandResult::Retry(());
            };
            match mac {
                Ok(inline_asm) => MacEager::items(smallvec![Box::new(ast::Item {
                    attrs: ast::AttrVec::new(),
                    id: ast::DUMMY_NODE_ID,
                    kind: ast::ItemKind::GlobalAsm(Box::new(inline_asm)),
                    vis: ast::Visibility {
                        span: sp.shrink_to_lo(),
                        kind: ast::VisibilityKind::Inherited,
                        tokens: None,
                    },
                    span: sp,
                    tokens: None,
                })]),
                Err(guar) => DummyResult::any(sp, guar),
            }
        }
        Err(err) => {
            let guar = err.emit();
            DummyResult::any(sp, guar)
        }
    })
}

pub fn is_in_macro_matcher(token: &SyntaxToken) -> bool {
    let Some(macro_def) = token
        .parent_ancestors()
        .map_while(Either::<ast::TokenTree, ast::Macro>::cast)
        .find_map(Either::right)
    else {
        return false;
    };
    let range = token.text_range();
    let Some(body) = (match macro_def {
        ast::Macro::MacroDef(macro_def) => {
            if let Some(args) = macro_def.args() {
                return args.syntax().text_range().contains_range(range);
            }
            macro_def.body()
        }
        ast::Macro::MacroRules(macro_rules) => macro_rules.token_tree(),
    }) else {
        return false;
    };
    if !body.syntax().text_range().contains_range(range) {
        return false;
    }
    body.token_trees_and_tokens().filter_map(|tt| tt.into_node()).any(|tt| {
        let Some(next) = non_trivia_sibling(tt.syntax().syntax_element(), Direction::Next) else {
            return false;
        };
        let Some(next_next) = next.next_sibling_or_token() else { return false };
        next.kind() == T![=]
            && next_next.kind() == T![>]
            && tt.syntax().text_range().contains_range(range)
    })
}

fn strip_hidden(cfg: &CfgEntry, hidden: &FxHashSet<NameValueCfg>) -> Option<CfgEntry> {
    match cfg {
        CfgEntry::Bool(..) => Some(cfg.clone()),
        CfgEntry::NameValue { .. } => {
            if !hidden.contains(&NameValueCfg::from(cfg)) {
                Some(cfg.clone())
            } else {
                None
            }
        }
        CfgEntry::Not(cfg, _) => {
            if let Some(cfg) = strip_hidden(cfg, hidden) {
                Some(CfgEntry::Not(Box::new(cfg), DUMMY_SP))
            } else {
                None
            }
        }
        CfgEntry::Any(cfgs, _) => {
            let cfgs =
                cfgs.iter().filter_map(|cfg| strip_hidden(cfg, hidden)).collect::<ThinVec<_>>();
            if cfgs.is_empty() { None } else { Some(CfgEntry::Any(cfgs, DUMMY_SP)) }
        }
        CfgEntry::All(cfgs, _) => {
            let cfgs =
                cfgs.iter().filter_map(|cfg| strip_hidden(cfg, hidden)).collect::<ThinVec<_>>();
            if cfgs.is_empty() { None } else { Some(CfgEntry::All(cfgs, DUMMY_SP)) }
        }
        CfgEntry::Version(..) => {
            // FIXME: Should be handled.
            Some(cfg.clone())
        }
    }
}

fn get_captured_ids(cx: &LateContext<'_>, ty: Ty<'_>) -> HirIdSet {
    fn get_captured_ids_recursive(cx: &LateContext<'_>, ty: Ty<'_>, set: &mut HirIdSet) {
        match ty.kind() {
            ty::Adt(_, generics) => {
                for generic in *generics {
                    if let GenericArgKind::Type(ty) = generic.kind() {
                        get_captured_ids_recursive(cx, ty, set);
                    }
                }
            },
            ty::Closure(def_id, _) => {
                let closure_hir_node = cx.tcx.hir_get_if_local(*def_id).unwrap();
                if let Node::Expr(closure_expr) = closure_hir_node {
                    can_move_expr_to_closure(cx, closure_expr)
                        .unwrap()
                        .into_iter()
                        .for_each(|(hir_id, capture_kind)| {
                            if matches!(capture_kind, CaptureKind::Ref(Mutability::Mut)) {
                                set.insert(hir_id);
                            }
                        });
                }
            },
            _ => (),
        }
    }

    let mut set = HirIdSet::default();

    get_captured_ids_recursive(cx, ty, &mut set);

    set
}

pub(super) fn check(cx: &LateContext<'_>, expr: &Expr<'_>, from: &Expr<'_>, to: &Ty<'_>) {
    if let TyKind::Ptr(ref ptr_ty) = to.kind {
        let init_expr = expr_or_init(cx, from);
        if is_expr_const_aligned(cx, init_expr, ptr_ty.ty)
            && let Some(std_or_core) = std_or_core(cx)
            && let pointee_ty = cx.typeck_results().node_type(ptr_ty.ty.hir_id)
            && pointee_ty.is_sized(cx.tcx, cx.typing_env())
        {
            let sugg_fn = match ptr_ty.mutbl {
                Mutability::Not => "ptr::dangling",
                Mutability::Mut => "ptr::dangling_mut",
            };

            let sugg = if let TyKind::Infer(()) = ptr_ty.ty.kind {
                format!("{std_or_core}::{sugg_fn}()")
            } else if let Some(mut_ty_snip) = ptr_ty.ty.span.get_source_text(cx) {
                format!("{std_or_core}::{sugg_fn}::<{mut_ty_snip}>()")
            } else {
                return;
            };

            span_lint_and_sugg(
                cx,
                MANUAL_DANGLING_PTR,
                expr.span,
                "manual creation of a dangling pointer",
                "use",
                sugg,
                Applicability::MachineApplicable,
            );
        }
    }
}

fn extend(
    cx: &mut AcceptContext<'_, '_>,
    args: &ArgParser,
) -> impl IntoIterator<Item = Self::Item> {
    let Some(list) = cx.expect_list(args, cx.attr_span) else {
        return vec![];
    };

    if list.is_empty() {
        cx.check_target(
            "()",
            &AllowedTargets::AllowList(&[
                Allow(Target::Struct),
                Allow(Target::Enum),
                Allow(Target::Union),
                Warn(Target::MacroCall),
            ]),
        );

        let attr_span = cx.attr_span;
        cx.adcx().warn_empty_attribute(attr_span);
        return vec![];
    }

    let mut reprs = Vec::new();
    for param in list.mixed() {
        let Some(item) = param.meta_item() else {
            cx.adcx().expected_identifier(param.span());
            continue;
        };
        reprs.extend(parse_repr(cx, &item).map(|r| (r, param.span())));
    }
    reprs
}

fn compile(&mut self) -> anyhow::Result<()> {
    let mut lcc_command = std::process::Command::new("llc");

    if let Some(mcpu) = &self.cpu {
        lcc_command.arg("--mcpu").arg(mcpu);
    }

    if let Some(mattr) = &self.feature {
        lcc_command.arg(&format!("--mattr={}", mattr));
    }

    let lcc_output = lcc_command
        .arg(&self.opt_path)
        .arg("-o").arg(&self.out_path)
        .output()
        .context("An error occurred when calling llc. Make sure the llvm-tools component is installed.")?;

    if !lcc_output.status.success() {
        tracing::error!(
            "llc returned with Exit status: {}\n stdout: {}\n stderr: {}",
            lcc_output.status,
            String::from_utf8(lcc_output.stdout).unwrap(),
            String::from_utf8(lcc_output.stderr).unwrap(),
        );

        anyhow::bail!(
            "llc failed to compile {} into {}",
            self.opt_path.display(),
            self.out_path.display()
        );
    }

    Ok(())
}

fn new(cx: &LateContext<'tcx>, hir_ty: &hir::Ty<'tcx>) -> Option<Self> {
    if let TyKind::Path(QPath::Resolved(None, path)) = hir_ty.kind {
        let params: Vec<_> = path
            .segments
            .last()
            .as_ref()?
            .args
            .as_ref()?
            .args
            .iter()
            .filter_map(|arg| match arg {
                GenericArg::Type(ty) => Some(ty),
                _ => None,
            })
            .collect();

        let ty = lower_ty(cx.tcx, hir_ty);

        match (ty.opt_diag_name(cx), &params[..]) {
            (Some(sym::HashMap), [k, v]) => Some(ImplicitHasherType::HashMap(
                hir_ty.span,
                ty,
                snippet(cx, k.span, "K"),
                snippet(cx, v.span, "V"),
            )),
            (Some(sym::HashSet), [t]) => {
                Some(ImplicitHasherType::HashSet(hir_ty.span, ty, snippet(cx, t.span, "T")))
            },
            _ => None,
        }
    } else {
        None
    }
}

fn join_assignments(
    edit: &mut TextEditBuilder,
    prev: &SyntaxElement,
    next: &SyntaxElement,
) -> Option<()> {
    let let_stmt = ast::LetStmt::cast(prev.as_node()?.clone())?;
    if let_stmt.eq_token().is_some() {
        cov_mark::hit!(join_assignments_already_initialized);
        return None;
    }
    let let_ident_pat = match let_stmt.pat()? {
        ast::Pat::IdentPat(it) => it,
        _ => return None,
    };

    let expr_stmt = ast::ExprStmt::cast(next.as_node()?.clone())?;
    let bin_expr = match expr_stmt.expr()? {
        ast::Expr::BinExpr(it) => it,
        _ => return None,
    };
    if !matches!(bin_expr.op_kind()?, ast::BinaryOp::Assignment { op: None }) {
        return None;
    }
    let lhs = bin_expr.lhs()?;
    let name_ref = expr_as_name_ref(&lhs)?;

    if name_ref.to_string() != let_ident_pat.syntax().to_string() {
        cov_mark::hit!(join_assignments_mismatch);
        return None;
    }

    edit.delete(let_stmt.semicolon_token()?.text_range().cover(lhs.syntax().text_range()));
    Some(())
}

fn prompt_user() -> io::Result<Option<EditorKind>> {
    let prompt_str = "Available editors:
1. Emacs
2. Helix
3. Vim
4. VS Code
5. Zed

Select which editor you would like to set up [default: None]: ";

    let mut input = String::new();
    loop {
        print!("{prompt_str}");
        io::stdout().flush()?;
        io::stdin().read_line(&mut input)?;

        let mut modified_input = input.to_lowercase();
        modified_input.retain(|ch| !ch.is_whitespace());
        match modified_input.as_str() {
            "1" | "emacs" => return Ok(Some(EditorKind::Emacs)),
            "2" | "helix" => return Ok(Some(EditorKind::Helix)),
            "3" | "vim" => return Ok(Some(EditorKind::Vim)),
            "4" | "vscode" => return Ok(Some(EditorKind::VsCode)),
            "5" | "zed" => return Ok(Some(EditorKind::Zed)),
            "" | "none" => return Ok(None),
            _ => {
                eprintln!("ERROR: unrecognized option '{}'", input.trim());
                eprintln!("NOTE: press Ctrl+C to exit");
            }
        }

        input.clear();
    }
}

fn check_fn(&mut self) {
    let def_id = self.item_id.expect_local();
    let span = self.tcx.def_span(def_id);

    if self.tcx.generics_of(def_id).requires_monomorphization(self.tcx) {
        self.tcx.dcx().emit_err(UnexportableItem::GenericFn(span));
        return;
    }

    let sig = self.tcx.fn_sig(def_id).instantiate_identity().skip_binder();
    if !matches!(sig.abi(), ExternAbi::C { .. }) {
        self.tcx.dcx().emit_err(UnexportableItem::FnAbi(span));
        return;
    }

    let sig = self
        .tcx
        .try_normalize_erasing_regions(
            ty::TypingEnv::non_body_analysis(self.tcx, def_id),
            Unnormalized::new_wip(sig),
        )
        .unwrap_or(sig);

    let hir_id = self.tcx.local_def_id_to_hir_id(def_id);
    let decl = self.tcx.hir_fn_decl_by_hir_id(hir_id).unwrap();

    for (input_ty, input_hir) in iter::zip(sig.inputs(), decl.inputs) {
        self.check_nested_types_are_exportable(*input_ty, input_hir.span);
    }

    if let hir::FnRetTy::Return(ret_hir) = decl.output {
        self.check_nested_types_are_exportable(sig.output(), ret_hir.span);
    }
}

fn test_update_weights_errors() {
    let data = [
        (
            &[1i32, 0, 0][..],
            &[(0, &0)][..],
            Error::InsufficientNonZero,
        ),
        (
            &[10, 10, 10, 10][..],
            &[(1, &-11)][..],
            Error::InvalidWeight, // A weight is negative
        ),
        (
            &[1, 2, 3, 4, 5][..],
            &[(1, &5), (0, &5)][..], // Wrong order
            Error::InvalidInput,
        ),
        (
            &[1][..],
            &[(1, &1)][..], // Index too large
            Error::InvalidInput,
        ),
    ];

    for (weights, update, err) in data.iter() {
        let total_weight = weights.iter().sum::<i32>();
        let mut distr = WeightedIndex::new(weights.to_vec()).unwrap();
        assert_eq!(distr.total_weight, total_weight);
        match distr.update_weights(update) {
            Ok(_) => panic!("Expected update_weights to fail, but it succeeded"),
            Err(e) => assert_eq!(e, *err),
        }
    }
}

pub fn read_permissions() -> Result<HashMap<String, Vec<PermissionFile>>, Error> {
  let mut permissions_map = HashMap::new();

  for (key, value) in env::vars_os() {
    let key = key.to_string_lossy();

    if let Some(plugin_crate_name_var) = key
      .strip_prefix("DEP_")
      .and_then(|v| v.strip_suffix(&format!("_{PERMISSION_FILES_PATH_KEY}")))
      .map(|v| {
        v.strip_suffix(CORE_PLUGIN_PERMISSIONS_TOKEN)
          .and_then(|v| v.strip_prefix("TAURI_"))
          .unwrap_or(v)
      })
    {
      let permissions_path = PathBuf::from(value);
      let permissions_str =
        fs::read_to_string(&permissions_path).map_err(|e| Error::ReadFile(e, permissions_path))?;
      let permissions: Vec<PathBuf> = serde_json::from_str(&permissions_str)?;
      let permissions = parse_permissions(permissions)?;

      let plugin_crate_name = plugin_crate_name_var.to_lowercase().replace('_', "-");
      let plugin_crate_name = plugin_crate_name
        .strip_prefix("tauri-plugin-")
        .map(ToString::to_string)
        .unwrap_or(plugin_crate_name);

      permissions_map.insert(plugin_crate_name, permissions);
    }
  }

  Ok(permissions_map)
}
